                {"image_resize", `{"src":"/uploads/banner.png","width":1200}`, "pending", 0, nil},
                {"email", `{"to":"bob@corp.io","subject":"Your invoice is ready"}`, "pending", 2, nil},
                {"data_export", `{"table":"orders","since":"2024-01-01"}`, "failed", 1, &w1},
